#include <stdio.h>

int main() {
    int brojac = 5; /* brojac za iteracije petlje */
    int n = 1; /* ovaj broj ce ici od 1 do n unutar petlje */
    long stari_faktorijel = 1; /* faktorijel prethodne vrijednosti (n-1) */
    long novi_faktorijel; /* vrijednost faktorijel(n) koja se treba izracunati */

    for (; brojac > 0; brojac--) {
        novi_faktorijel = stari_faktorijel * n;
        printf("Faktorijel(%d) = %ld " , n, novi_faktorijel);
        n++;
        stari_faktorijel = novi_faktorijel;
    }
        
    return 0;
}
